func (t Types) GetFirstBySuffix(suffix string) (Type, SuffixInfo, bool) {
	suffix = strings.ToLower(suffix)
	for _, tt := range t {
		if tt.hasSuffix(suffix) {
			return tt, SuffixInfo{
				FullSuffix:	tt.Delimiter + suffix,
				Suffix:		suffix,
			}, true
		}
	}
	return Type{}, SuffixInfo{}, false
}
